{
  "mode": "method",
  "tests": [
    {
      "name": "valid_submission_phase_display",
      "input": {
        "challengeId": 123,
        "phase": "submission"
      },
      "output": {
        "display": "Submission Phase Active"
      },
      "notes": "Validates that the submission phase is displayed correctly for a challenge."
    },
    {
      "name": "invalid_phase_display",
      "input": {
        "challengeId": 456,
        "phase": "invalid"
      },
      "output": {
        "error": "Invalid phase"
      },
      "notes": "Checks that an error is returned for an invalid phase."
    },
    {
      "name": "no_phase_display",
      "input": {
        "challengeId": 789
      },
      "output": {
        "error": "Phase not specified"
      },
      "notes": "Ensures that an error is returned when no phase is specified."
    },
    {
      "name": "multiple_rounds_display",
      "input": {
        "challengeId": 101,
        "rounds": 2,
        "phase": "submission"
      },
      "output": {
        "display": "Submission Phase Active for Round 1 and Round 2"
      },
      "notes": "Validates that the submission phase is displayed correctly for multiple rounds."
    },
    {
      "name": "future_phase_display",
      "input": {
        "challengeId": 202,
        "phase": "future"
      },
      "output": {
        "error": "Phase not yet started"
      },
      "notes": "Checks that an error is returned for a phase that has not started."
    },
    {
      "name": "completed_phase_display",
      "input": {
        "challengeId": 303,
        "phase": "completed"
      },
      "output": {
        "error": "Phase has already completed"
      },
      "notes": "Validates that an error is returned for a completed phase."
    },
    {
      "name": "edge_case_empty_challenge_id",
      "input": {
        "challengeId": null,
        "phase": "submission"
      },
      "output": {
        "error": "Challenge ID cannot be null"
      },
      "notes": "Tests the edge case where the challenge ID is null."
    },
    {
      "name": "edge_case_nonexistent_challenge",
      "input": {
        "challengeId": 999999,
        "phase": "submission"
      },
      "output": {
        "error": "Challenge does not exist"
      },
      "notes": "Tests the edge case where the challenge ID does not exist."
    }
  ],
  "assumptions": "All challenge IDs are integers and phases are strings.",
  "notes": "Ensure that the submission phase display logic is thoroughly tested."
}
